Rules.InvariantScript:
UpdateContext(
    {
        locLoadingText: "Gettings things ready...",
        locLoadingPercent: 0
    }
);
If(
    gblAppAutoload,
    Select(btn_Loading_VersionCheck)
)

Trace("Button Pressed: Loading Step X",TraceSeverity.Information);
If(
    // Connected
    Connection.Connected,
    UpdateContext(
        {
            locLoadingText: "Checking App version...",
            locLoadingPercent: 5
        }
    );
    UpdateContext(
        // Check CDS for Power App Cache
        {
            locPowerAppCache: First(
                Filter(
                    'Power App Caches',
                    'Power App Caches (Views)'.'Vesta Measure'
                )
            )
        }
    );
    If(
            // If User is not on correct version, redirect to screen to prompt update
        locPowerAppCache.'App Version' = gblAppVersion,
        Select(btn_Loading_OptionSets),
        Navigate('Incorrect Version Screen');
    ),
    // Not Connected
    LoadData(
        colCdsOptionSets,
        "localCdsOptionSets",
        true
    );
    Set(
        gblOptionSets,
        First(colCdsOptionSets)
    );
    If(
        IsEmpty(colCdsOptionSets),
        Notify(
            "You are offline and the app has not been configured. Please try again, when online.",
            NotificationType.Error
        ),
        Select(btn_Loading_LoadLocalFiles);
    )
);

Trace("Button Pressed: Loading Step 0",TraceSeverity.Information);
UpdateContext(
    {
        locLoadingText: "Checking Vesta Data...",
        locLoadingPercent: 10
    }
);
If(
    gblAppLoadOffline,
    LoadData(
        colCdsOptionSets,
        "localCdsOptionSets",
        true
    )
);
Set(
    gblOptionSets,
    First(colCdsOptionSets)
);
If(
    gblOptionSets.TimeStamp < locPowerAppCache.'Option Sets' Or IsEmpty(colCdsOptionSets),
    Set(
        gblOptionSets,
        {
            TimeStamp: locPowerAppCache.'Option Sets',
            Global: {
                PhotoType: {
                    Window: 'Photo Type'.Window,
                    ElevationSide: 'Photo Type'.'Elevation (Side)',
                    ElevationFront: 'Photo Type'.'Elevation (Front)',
                    ElevationRear: 'Photo Type'.'Elevation (Rear)',
                    Other: 'Photo Type'.Other
                },
                DataEntryType: {
                    Construction: 'Data Entry Type'.Construction,
                    ExistingWindows: 'Data Entry Type'.'Existing Windows',
                    ExteriorCapping: 'Data Entry Type'.'Exterior Capping',
                    ExteriorCovering: 'Data Entry Type'.'Exterior Covering',
                    ExteriorWindowComponent: 'Data Entry Type'.'Exterior Window Component',
                    Floor: 'Data Entry Type'.Floor,
                    InteriorWindowComponent: 'Data Entry Type'.'Interior Window Component',
                    LeadTestResults: 'Data Entry Type'.'Lead Test Results',
                    LumberGrade: 'Data Entry Type'.'Lumber Grade',
                    LumberSpecies: 'Data Entry Type'.'Lumber Species',
                    Room: 'Data Entry Type'.Room,
                    SpecialConditions: 'Data Entry Type'.'Special Conditions',
                    SpecialEquipmentNeeded: 'Data Entry Type'.'Special Equipment Needed',
                    StyleOfHome: 'Data Entry Type'.'Style Of Home'
                },
                YesNoNull: {
                    Yes: 'Yes No Null'.Yes,
                    No: 'Yes No Null'.No
                }
            },
            Job: {
                CompletedJob: {
                    Yes: 'Completed (Jobs)'.Yes,
                    No: 'Completed (Jobs)'.No
                },
                LeadTestSendDocuments: {
                    Yes: 'Lead Test: Send Document? (Jobs)'.Yes,
                    No: 'Lead Test: Send Document? (Jobs)'.No
                },
                IsSourceVestaDeal: {
                    Yes: 'Is Source Vesta Deal? (Jobs)'.Yes,
                    No: 'Is Source Vesta Deal? (Jobs)'.No
                },
                JobPackageSendDocuments: {
                    Yes: 'Job Package: Send Documents? (Jobs)'.Yes,
                    No: 'Job Package: Send Documents? (Jobs)'.No
                },
                JobFinishedSendEmail: {
                    Yes: 'Job Finished: Send Email? (Jobs)'.Yes,
                    No: 'Job Finished: Send Email? (Jobs)'.No
                }
            },
            JobPhoto: {
                Status: {
                    Inactive: 'Status (Job Photos)'.Inactive,
                    Active: 'Status (Job Photos)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Job Photos)'.Inactive}
            },
            JobRoom: {
                Status: {
                    Inactive: 'Status (Job Rooms)'.Inactive,
                    Active: 'Status (Job Rooms)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Job Rooms)'.Inactive}
            },
            JobLaborItem: {
                Status: {
                    Active: 'Status (Job Labor Items)'.Active,
                    Inactive: 'Status (Job Labor Items)'.Inactive
                },
                StatusReason: {
                    Active: 'Status Reason (Job Labor Items)'.Active,
                    Inactive: 'Status Reason (Job Labor Items)'.Inactive
                }
            },
            JobMaterialItem: {
                Status: {
                    Inactive: 'Status (Job Material Items)'.Inactive,
                    Active: 'Status (Job Material Items)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Job Material Items)'.Inactive}
            },
            JobEntrySelection: {
                Status: {
                    Inactive: 'Status (Job Entry Selections)'.Inactive,
                    Active: 'Status (Job Entry Selections)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Job Entry Selections)'.Inactive}
            },
            JobEntry: {
                Completed: {
                    Yes: 'Completed (Job Entries)'.Yes,
                    No: 'Completed (Job Entries)'.No
                },
                IsSourceVestaDeal: {
                    Yes: 'Is Source Vesta Deal? (Jobs)'.Yes,
                    No: 'Is Source Vesta Deal? (Jobs)'.No
                },
                Status: {
                    Inactive: 'Status (Job Entries)'.Inactive,
                    Active: 'Status (Job Entries)'.Active
                },
                LeadTestResult: {
                    Yes: 'Yes No Null'.Yes,
                    No: 'Yes No Null'.No
                },
                StatusReason: {Inactive: 'Status Reason (Job Entries)'.Inactive}
            },
            JobEntryOption: {
                IsLegacy: {
                    Yes: 'Legacy? (Job Entry Options)'.Yes,
                    No: 'Legacy? (Job Entry Options)'.No
                },
                Status: {
                    Inactive: 'Status (Job Entry Options)'.Inactive,
                    Active: 'Status (Job Entry Options)'.Active
                },
                Type: {
                    Attribute: 'Job Entry Option Types'.Attribute,
                    Header: 'Job Entry Option Types'.Header,
                    HierarchyStep: 'Job Entry Option Types'.'Hierarchy Step',
                    Value: 'Job Entry Option Types'.Value
                }
            },
            MaterialItems: {
                Type: {
                        CaulkCoil: 'Material Item Type'.CAULK,
                        Lumber: 'Material Item Type'.COIL,
                        RoofingSiding: 'Material Item Type'.'FOAM/CLEANER/INSULATION',
                        LeadSupplies: 'Material Item Type'.'LEAD SUPPLIES'
                },
                TypeTable: Table(
                    {Value: 'Material Item Type'.CAULK},
                    {Value: 'Material Item Type'.COIL},
                    {Value: 'Material Item Type'.'FOAM/CLEANER/INSULATION'},
                    {Value: 'Material Item Type'.'LEAD SUPPLIES'}
                )
            },
            WindowChoices: {
                IncludeJambDepth: {
                    Yes: 'Include Jamb Depth (Window Choices)'.Yes,
                    No: 'Include Jamb Depth (Window Choices)'.No
                },
                IncludeMaxProjection: {
                    Yes: 'Include Max Projection (Window Choices)'.Yes,
                    No: 'Include Max Projection (Window Choices)'.No
                },
                IncludeSoffitDepth: {
                    Yes: 'Include Soffit Depth (Window Choices)'.Yes,
                    No: 'Include Soffit Depth (Window Choices)'.No
                },
                IncludeWallThickness: {
                    Yes: 'Include Wall Thickness (Window Choices)'.Yes,
                    No: 'Include Wall Thickness (Window Choices)'.No
                }
            },
            WindowMeasurement: {
                Completed: {
                    Yes: 'Completed (Window Measurements)'.Yes,
                    No: 'Completed (Window Measurements)'.No
                },
                Exception: {
                    Yes: 'Exception? (Window Measurements)'.Yes,
                    No: 'Exception? (Window Measurements)'.No
                },
                LeadTestResult: {
                    Yes: 'Yes No Null'.Yes,
                    No: 'Yes No Null'.No
                },
                Status: {
                    Inactive: 'Status (Window Measurements)'.Inactive,
                    Active: 'Status (Window Measurements)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Window Measurements)'.Inactive},
                Type: {
                    Sales: 'Window Measurement Types'.Sales,
                    Tech: 'Window Measurement Types'.Tech,
                    Other: 'Window Measurement Types'.Other
                }
            },
            WindowMull: { 
                Status: {
                    Inactive: 'Status (Window Mulls)'.Inactive,
                    Active: 'Status (Window Mulls)'.Active
                },
                StatusReason: {Inactive: 'Status Reason (Window Mulls)'.Inactive}
            },
            JobDocument: {
                Completed: {
                    Yes: 'Completed (Job Documents)'.Yes,
                    No: 'Completed (Job Documents)'.No
                },
                Status: {
                    Active: 'Status (Job Documents)'.Active
                }
            }
        }
    );
    ClearCollect(
        colCdsOptionSets,
        gblOptionSets
    );
    If(
        gblAppLoadOffline,
        SaveData(
            colCdsOptionSets,
            "localCdsOptionSets"
        )
    )
);
// Navigate
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Loading local data...",
            locLoadingPercent: 15
        }
    );
    Select(btn_Loading_LoadLocalFiles)
);

Trace(
    "Button Pressed: Loading Step 1",
    TraceSeverity.Information
    );


IfError(   // ✅ Start error handler

If(
    gblAppLoadOffline,
    // UNSAVED JOBS
    LoadData(
        colAUDRecords,
        "localAUDRecords",
        true
    );
    If(
        !IsEmpty(colAUDRecords),
        UpdateContext(
            {
                locLoadingText: "Resuming last session...",
                locLoadingPercent: 80
            }
        )
    )
);
If(
    !locLoadingSkipLocal,
    If(
        gblAppLoadOffline,
// ACCOUNTS
            LoadData(
                colCdsAccounts,
                "localCdsAccounts",
                true
            );
// DOCUMENTS
            LoadData(
                colCdsDocuments,
                "localCdsDocuments",
                true
            );
// DATA ENTRY CHOICES
            LoadData(
                colCdsDataEntryChoices,
                "localCdsDataEntryChoices",
                true
            );
// EMPLOYEES
            LoadData(
                colCdsEmployees,
                "localCdsEmployees",
                true
            );
// JOB DOCUMENTS
            LoadData(
                colCdsJobDocuments,
                "localCdsJobDocuments",
                true
            );
// JOB ENTRIES
            LoadData(
                colCdsJobEntries,
                "localCdsJobEntries",
                true
            );
// JOB ENTRY OPTIONS
            Clear(colCdsJobEntryOptions);
            LoadData(
                colStagingCdsJobEntryOptions_Header,
                "localCdsJobEntryOptions_Header",
                true
            );
            LoadData(
                colStagingCdsJobEntryOptions_Attribute,
                "localCdsJobEntryOptions_Attribute",
                true
            );
            LoadData(
                colStagingCdsJobEntryOptions_HierarchyStep,
                "localCdsJobEntryOptions_HierarchyStep",
                true
            );
            LoadData(
                colStagingCdsJobEntryOptions_Value,
                "localCdsJobEntryOptions_Value",
                true
            );
            Collect(
                colCdsJobEntryOptions,
                colStagingCdsJobEntryOptions_Header
            );
            Collect(
                colCdsJobEntryOptions,
                colStagingCdsJobEntryOptions_Attribute
            );
            Collect(
                colCdsJobEntryOptions,
                colStagingCdsJobEntryOptions_HierarchyStep
            );
            Collect(
                colCdsJobEntryOptions,
                colStagingCdsJobEntryOptions_Value
            );
            Clear(colStagingCdsJobEntryOptions_Header);
            Clear(colStagingCdsJobEntryOptions_Attribute);
            Clear(colStagingCdsJobEntryOptions_HierarchyStep);
            Clear(colStagingCdsJobEntryOptions_Value);
// JOB ENTRY SELECTIONS
            LoadData(
                colCdsJobEntrySelections,
                "localCdsJobEntrySelections",
                true
            );
// JOB LABOR ITEMS
            LoadData(
                colCdsJobLaborItems,
                "localCdsJobLaborItems",
                true
            );
// JOB MATERIAL ITEMS
            LoadData(
                colCdsJobMaterialItems,
                "localCdsJobMaterialItems",
                true
            );
// JOB PHOTOS
            LoadData(
                colCdsJobPhotos,
                "localCdsJobPhotos",
                true
            );
// JOB ROOMS
            LoadData(
                colCdsJobRooms,
                "localCdsJobRooms",
                true
            );
// JOBS
            LoadData(
                colCdsJobs,
                "localCdsJobs",
                true
            );
// JOB STAGES
            LoadData(
                colCdsJobStages,
                "localCdsJobStages",
                true
            );
// LABOR ITEMS
            LoadData(
                colCdsLaborItems,
                "localCdsLaborItems",
                true
            );
// MARKET LABOR ITEMS
            LoadData(
                colCdsMarketLaborItems,
                "localCdsMarketLaborItems",
                true
            );
// MARKET MATERIAL ITEMS
            LoadData(
                colCdsMarketMaterialItems,
                "localCdsMarketMaterialItems",
                true
            );
// MARKET SEGMENTS
            LoadData(
                colCdsMarketSegments,
                "localCdsMarketSegments",
                true
            );
// MATERIAL ITEMS
            LoadData(
                colCdsMaterialItems,
                "localCdsMaterialItems",
                true
            );
// MATERIAL ITEM COLORS
            LoadData(
                colCdsMaterialItemColors,
                "localCdsMaterialItemColors",
                true
            );
// ROOMS
            LoadData(
                colCdsRooms,
                "localCdsRooms",
                true
            );
// VESTA SETTINGS
            LoadData(
        colCdsVestaSettings,
        "localCdsVestaSettings",
        true
    );
// WINDOW CHOICES
            LoadData(
                colCdsWindowChoices,
                "localCdsWindowChoices",
                true
            );
// WINDOW MEASUREMENTS
            LoadData(
                colCdsWindowMeasurements,
                "localCdsWindowMeasurements",
                true
            );
// WINDOW MODELS
            LoadData(
                colCdsWindowModels,
                "localCdsWindowModels",
                true
            );
// WINDOW MULLS
            LoadData(
                colCdsWindowMulls,
                "localCdsWindowMulls",
                true
            );
// WINDOW STYLES
            LoadData(
                colCdsWindowStyles,
                "localCdsWindowStyles",
                true
            );
        )
);
If(
    gblAppAutoAdvance,
    If(
        !IsEmpty(colAUDRecords) Or !Connection.Connected,
        Select(btn_Loading_Proceed),
        // Resume last session; loading text set above
        UpdateContext(
            {
                locLoadingText: "Checking Vesta Data...",
                locLoadingPercent: 20
            }
        );
        Select(btn_Loading_CheckCdsOrg)
    )
);
, Blank() )  // ✅ Suppress any visible error

Trace(
    "Button Pressed: Loading Step 2.1",
    TraceSeverity.Information
);
// Compare CDS Modified Ons
UpdateContext(
    {
        locCdsOrgLatest_Accounts: locPowerAppCache.Accounts,
        locCdsOrgLatest_Documents: locPowerAppCache.Documents,
        locCdsOrgLatest_DataEntryChoices: locPowerAppCache.'Data Entry Choices',
        locCdsOrgLatest_Employee: locPowerAppCache.Employees,
        locCdsOrgLatest_JobEntryOptions_Headers: locPowerAppCache.'Job Entry Options (Headers)',
        locCdsOrgLatest_JobEntryOptions_Attributes: locPowerAppCache.'Job Entry Options (Attributes)',
        locCdsOrgLatest_JobEntryOptions_HierarchySteps: locPowerAppCache.'Job Entry Options (Hierarchy Steps)',
        locCdsOrgLatest_JobEntryOptions_Values: locPowerAppCache.'Job Entry Options (Values)',
        locCdsOrgLatest_JobStages: locPowerAppCache.'Job Stages',
        locCdsOrgLatest_LaborItems: locPowerAppCache.'Labor Items',
        locCdsOrgLatest_MaterialItemColors: locPowerAppCache.'Material Item Colors',
        locCdsOrgLatest_MarketSegments: locPowerAppCache.'Market Segments',
        locCdsOrgLatest_MaterialItems: locPowerAppCache.'Material Items',
        locCdsOrgLatest_Rooms: locPowerAppCache.Rooms,
        locCdsOrgLatest_VestaSettings: Now(),
        locCdsOrgLatest_WindowChoices: locPowerAppCache.'Window Choices',
        locCdsOrgLatest_WindowModels: locPowerAppCache.'Window Models',
        locCdsOrgLatest_WindowStyles: locPowerAppCache.'Window Styles',
        locCdsOrgLatest_MarketMaterialItems:locPowerAppCache.'Market Material Items'
    }
);
UpdateContext(
    {
        locCdsOrgLatest_JobEntryOptions: Max(
            locCdsOrgLatest_JobEntryOptions_Attributes,
            locCdsOrgLatest_JobEntryOptions_Headers,
            locCdsOrgLatest_JobEntryOptions_HierarchySteps,
            locCdsOrgLatest_JobEntryOptions_Values
        )
    }
);
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Loading Vesta Data...",
            locLoadingPercent: 25
        }
    );
    Select(btn_Loading_LoadCdsOrg);

)

Trace("Button Pressed: Loading Step 2.2",TraceSeverity.Information);
Clear(colCdsMarketMaterialItems);
Concurrent(
// ACCOUNTS
    If(
        First(
            SortByColumns(
                colCdsAccounts,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_Accounts Or IsEmpty(colCdsAccounts),
        ClearCollect(
            colCdsAccounts,
            Filter(
                Accounts,
                'Accounts (Views)'.'Active Manufacturer Accounts'
            )
        );
        UpdateContext({locSaveAccounts: true})
    ),
 // DATA ENTRY CHOICES
    If(
        First(
            SortByColumns(
                colCdsDataEntryChoices,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_DataEntryChoices Or IsEmpty(colCdsDataEntryChoices),
        ClearCollect(
            colCdsDataEntryChoices,
            Filter(
                'Data Entry Choices',
                'Data Entry Choices (Views)'.'Active Data Entry Choices'
            )
        );
        UpdateContext({locSaveDataEntryChoices: true})
    ),
// DOCUMENTS
    If(
        First(
            SortByColumns(
                colCdsDocuments,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_Documents Or IsEmpty(colCdsDocuments),
        ClearCollect(
            colCdsDocuments,
            Filter(
                Documents,
                'Documents (Views)'.'Active Documents'
            )
        );
        UpdateContext({locSaveDocuments: true})
    ),
    // EMPLOYEES
    If(
        First(
            SortByColumns(
                colCdsEmployees,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_Employee Or IsEmpty(colCdsEmployees),
        ClearCollect(
            colCdsEmployees,
            Filter(
                Employees,
                'Employees (Views)'.'Active Employees'
            )
        );
        UpdateContext({locSaveEmployees: true})
    ),
	// JOB STAGES
    If(
        First(
            SortByColumns(
                colCdsJobStages,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_JobStages Or IsEmpty(colCdsJobStages),
        ClearCollect(
            colCdsJobStages,
            Filter(
                'Job Stages',
                'Job Stages (Views)'.'Active Job Stages'
            )
        );
        UpdateContext({locSaveJobStages: true})
    ),
	// LABOR ITEMS
    If(
        First(
            SortByColumns(
                colCdsLaborItems,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_LaborItems Or IsEmpty(colCdsLaborItems),
        ClearCollect(
            colCdsLaborItems,
            AddColumns(
                Filter(
                    'Labor Items',
                    'Labor Items (Views)'.'Active Labor Items'
                ),
                appOptionSetType,
                Type
            )
        );
        UpdateContext({locSaveLaborItems: true})
    ),
// MARKET SEGMENTS
    If(
        First(
            SortByColumns(
                colCdsMarketSegments,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_MarketSegments Or IsEmpty(colCdsMarketSegments),
        ClearCollect(
            colCdsMarketSegments,
            Filter(
                'Market Segments',
                'Market Segments (Views)'.'Active Market Segments'
            )
        );
        UpdateContext({locSaveMarketSegments: true})
    ),
// MATERIAL ITEMS
    If(
        First(
            SortByColumns(
                colCdsMaterialItems,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_MaterialItems Or IsEmpty(colCdsMaterialItems),
        ClearCollect(
            colCdsMaterialItems,
            AddColumns(
                Filter(
                    'Material Items',
                    'Material Items (Views)'.'Active Material Items'
                ),
                appOptionSetType,
                Type
            )
        );
        UpdateContext({locSaveMaterialItems: true})
    ),
// MATERIAL ITEM COLORS
    If(
        First(
            SortByColumns(
                colCdsMaterialItemColors,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_MaterialItemColors Or IsEmpty(colCdsMaterialItemColors),
        ClearCollect(
            colCdsMaterialItemColors,
            Filter(
                'Material Item Colors',
                'Material Item Colors (Views)'.'Active Material Item Colors'
            )
        );
        UpdateContext({locSaveMaterialItemColors: true})
    ),

    //MARKET MATERIAL ITEMS
    If(  
        First(
            SortByColumns(
                colCdsMarketMaterialItems,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_MarketMaterialItems Or IsEmpty(colCdsMarketMaterialItems),
 ClearCollect(
    colCdsMarketSegmentsIds,
    Distinct('Market Segments', 'Market Segment')
);
ForAll(
    colCdsMarketSegmentsIds,
    Collect(
        colCdsMarketMaterialItems,
        Filter(
            'Market Material Items',
            'Market Segment'.'Market Segment'= colCdsMarketSegmentsIds[@Value]
        )
    )
);
        UpdateContext({locSaveMarketMaterialItems: true})
    ),


// ROOMS
    If(
        First(
            SortByColumns(
                colCdsRooms,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_Rooms Or IsEmpty(colCdsRooms),
        ClearCollect(
            colCdsRooms,
            AddColumns(
                Filter(
                    Rooms,
                    'Rooms (Views)'.'Active Rooms'
                ),
                appRoomIdText,
                Text(Room)
            )
        );
        UpdateContext({locSaveRooms: true})
    ),
   // VESTA SETTINGS
   If(
        First(
            SortByColumns(
                colCdsVestaSettings,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_VestaSettings Or IsEmpty(colCdsVestaSettings),
        ClearCollect(
            colCdsVestaSettings,
            Filter(
                'Vesta Settings',
                'Vesta Settings (Views)'.'Active Vesta Measure Settings'
            )
        );
        UpdateContext({locSaveVestaSettings: true})
   ),
// WINDOW CHOICES
    If(
        First(
            SortByColumns(
                colCdsWindowChoices,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_WindowChoices Or IsEmpty(colCdsWindowChoices),
        ClearCollect(
            colCdsWindowChoices,
            AddColumns(
                Filter(
                    'Window Choices',
                    'Window Choices (Views)'.'Active Window Choices'
                ),
                appWindowStyleIdText,
                Text(Style.'Window Style'),
                appWindowModelIdText,
                Text(Model.'Window Model'),
                appAccountsIdText,
                Text(Manufacturer.Account),
                appJobEntryOptionIdText,
                Text('Job Entry Option (Header)'.'Job Entry Option')
            )
        );
        UpdateContext({locSaveWindowChoices: true})
    ),
// WINDOW MODELS
    If(
        First(
            SortByColumns(
                colCdsWindowModels,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_WindowModels Or IsEmpty(colCdsWindowModels),
        ClearCollect(
            colCdsWindowModels,
            Filter(
                'Window Models',
                'Window Models (Views)'.'Active Window Models'
            )
        );
        UpdateContext({locSaveWindowModels: true})
    ),
// WINDOW STYLES
    If(
        First(
            SortByColumns(
                colCdsWindowStyles,
                "modifiedon",
                SortOrder.Descending
            )
        ).'Modified On' < locCdsOrgLatest_WindowStyles Or IsEmpty(colCdsWindowStyles),
        ClearCollect(
            colCdsWindowStyles,
            Filter(
                'Window Styles',
                'Window Styles (Views)'.'Active Window Styles'
            )
        );
        UpdateContext({locSaveWindowStyles: true})
    )
);
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Caching Vesta Data...",
            locLoadingPercent: 40
        }
    );
    Select(btn_Loading_SaveCdsOrg)
)

